// Base class: Employee
class Employee {
  constructor(
    public name: string,
    protected salary: number,
    private id: number
  ) {}
  // Public method accessible from anywhere
  getDetails(): string {
    return `Employee: ${this.name}, ID: ${this.id}`;
  }
  // Protected method accessible in this class and subclasses
  protected getSalary(): number {
    return this.salary;
  }
}
// Subclass: Manager extends Employee
class Manager extends Employee {
  constructor(
    name: string,
    salary: number,
    id: number,
    public teamSize: number
  ) {
    super(name, salary, id); // Call parent constructor
  }
  // Override parent method with more detail
  getDetails(): string {
    return `${super.getDetails()}, Team: ${this.teamSize} people`;
  }
}
const emp = new Manager('Alice', 85000, 101, 5);
console.log(emp.getDetails());
// Expected: Employee: Alice, ID: 101, Team: 5 people
